    /// Eased entrance progress in [0, 1] for the requested overlay. Returns
    /// 1.0 when the overlay isn't open or reduce-motion is active.
    pub fn overlay_enter(&self, key: OverlayKey, duration_secs: f32) -> f32 {
        let at = match key {
            OverlayKey::Help => self.help_opened_at,
            OverlayKey::QuitConfirm => self.quit_confirm_opened_at,
            OverlayKey::Properties => self.properties_opened_at,
            OverlayKey::PlatformDebug => self.platform_debug_opened_at,
            OverlayKey::Wizard => self.wizard_opened_at,
            OverlayKey::Stopping => self.stopping_opened_at,
            OverlayKey::EventLog => self.event_log_opened_at,
            OverlayKey::TextInput => self.text_input_opened_at,
            OverlayKey::PluginBrowser => self.plugin_browser_opened_at,
            OverlayKey::Palette => self.palette_opened_at,
            OverlayKey::ActionsPopup => self.actions_popup_opened_at,
            OverlayKey::DagOverlay => self.dag_overlay_opened_at,
        };
        let Some(at) = at else {
            return 1.0;
        };
        if crate::tui::anim::reduce_motion() {
            return 1.0;
        }
        let raw = (at.elapsed().as_secs_f32() / duration_secs).clamp(0.0, 1.0);
        crate::tui::anim::easing::Ease::Standard.apply(raw)
    }

    /// Must be called once per frame before widgets render. Keeps overlay
    /// `opened_at` fields in sync with their boolean / Option flags and
    /// resets timestamps when overlays open or close.
    pub fn update_overlay_timing(&mut self) {
        sync_open(&mut self.help_opened_at, self.show_help);
        sync_open(&mut self.quit_confirm_opened_at, self.quit_confirm);
        sync_open(
            &mut self.properties_opened_at,
            self.show_properties.is_some(),
        );
        sync_open(
            &mut self.platform_debug_opened_at,
            self.show_platform_debug.is_some(),
        );
        let wizard_live = self.active_pane == ActivePane::Wizard || self.pending_auth.is_some();
        sync_open(&mut self.wizard_opened_at, wizard_live);
        sync_open(
            &mut self.stopping_opened_at,
            self.stop_all_deadline.is_some(),
        );
        sync_open(&mut self.event_log_opened_at, self.show_event_log);
        sync_open(&mut self.text_input_opened_at, self.text_input.is_some());
        sync_open(
            &mut self.plugin_browser_opened_at,
            self.show_plugin_browser,
        );
        sync_open(&mut self.palette_opened_at, self.palette.is_some());
        sync_open(
            &mut self.actions_popup_opened_at,
            self.actions_popup.is_some(),
        );
        sync_open(&mut self.dag_overlay_opened_at, self.show_dag_overlay);
        // Drop terminal tasks 2 seconds after they enter the Done/Failed
        // state — long enough for the user to read the result, short
        // enough to keep the tail clean.
        self.tasks.reap(std::time::Duration::from_secs(2));
    }

    /// Seconds since the active pane last changed. Used by widget borders to
    /// ramp in a cyan glow on focus (see `Theme::border_focused_ramp`).
    pub fn focus_fade_secs(&self) -> f32 {
        self.pane_focus_at.elapsed().as_secs_f32()
    }

    /// Must be called once per frame before widgets render so pane-focus
    /// transitions get a fresh start timestamp when the active pane changes.
    pub fn update_focus_timing(&mut self) {
        if self.prev_render_pane != self.active_pane {
            self.pane_lost_focus = Some(self.prev_render_pane.clone());
            self.pane_focus_at = std::time::Instant::now();
            self.prev_render_pane = self.active_pane.clone();
            // Persist last pane to state.json (skipping non-restorable
            // panes like Wizard / Plugin).
            if let Some(label) = self.active_pane.label() {
                let stored = self.state.last_pane.as_deref();
                if stored != Some(label) {
                    self.state.last_pane = Some(label.to_string());
                    self.state.save();
                }
            }
        } else if self.pane_lost_focus.is_some()
            && self.pane_focus_at.elapsed().as_secs_f32() > 0.14
        {
            // Unfocused ramp has settled — stop drawing it.
            self.pane_lost_focus = None;
        }
    }

    /// Returns `true` when at least one animation is live, so the TUI run
    /// loop should stay at the 16 ms fast cadence. When everything is quiet
    /// it drops to a slower poll (see `poll_duration`) to conserve CPU.
    pub fn needs_fast_frame(&self) -> bool {
        // Always-on surfaces with periodic motion.
        if self.theme_picker.is_some() {
            return true;
        }
        if self.search_active {
            return true;
        }
        if self.active_recording_count() > 0 {
            return true;
        }
        // Anything resolving or stopping is animated.
        let has_transient_state = self.recordings.values().any(|r| {
            matches!(
                r.state,
                crate::recording::job::RecordingState::ResolvingUrl
                    | crate::recording::job::RecordingState::Stopping
                    | crate::recording::job::RecordingState::Failed
            )
        });
        if has_transient_state {
            return true;
        }
        // Any live channel pulses the LIVE badge in channel_detail.
        if self.channels.iter().any(|c| c.is_live) {
            return true;
        }
        // Transient bounded animations — check whether their timer is still
        // within the active window (with slack to cover the tail).
        let within = |at: Option<std::time::Instant>, limit_secs: f32| -> bool {
            at.map(|t| t.elapsed().as_secs_f32() < limit_secs)
                .unwrap_or(false)
        };
        if within(self.last_hotkey_at, 0.28) {
            return true;
        }
        if within(Some(self.pane_focus_at), 0.22) {
            return true;
        }
        if within(self.help_opened_at, 0.22)
            || within(self.quit_confirm_opened_at, 0.22)
            || within(self.properties_opened_at, 0.22)
            || within(self.platform_debug_opened_at, 0.22)
            || within(self.wizard_opened_at, 0.28)
            || within(self.stopping_opened_at, 0.22)
        {
            return true;
        }
        if within(self.daemon_disconnected_at, 0.24) {
            return true;
        }
        if self
            .thumbnail_changed_at
            .values()
            .any(|t| t.elapsed().as_secs_f32() < 0.65)
        {
            return true;
        }
        if self
            .status_message_at
            .map(|t| t.elapsed().as_secs_f32() > 4.3 && t.elapsed().as_secs_f32() < 5.2)
            .unwrap_or(false)
        {
            // Toast fade window.
            return true;
        }
        false
    }

    /// Frame duration to use for this frame. 16 ms when something is
    /// animating, 120 ms when the UI is quiescent.
    pub fn poll_duration(&self) -> std::time::Duration {
        if crate::tui::anim::reduce_motion() {
            return std::time::Duration::from_millis(120);
        }
        if self.needs_fast_frame() {
            std::time::Duration::from_millis(16)
        } else {
            std::time::Duration::from_millis(120)
        }
    }

    /// Border style for a pane, picking the right focus animation.
    ///
    /// - Currently active pane → dim → primary fade-in (180 ms).
    /// - Pane that just lost focus → primary → dim fade-out (120 ms).
    /// - Otherwise → static dim.
    pub fn pane_border(&self, this: &ActivePane) -> ratatui::style::Style {
        use crate::tui::theme::Theme;
        if self.active_pane == *this {
            Theme::border_focused_ramp(self.focus_fade_secs())
        } else if self.pane_lost_focus.as_ref() == Some(this) && self.focus_fade_secs() < 0.14 {
            Theme::border_unfocused_ramp(self.focus_fade_secs())
        } else {
            Theme::border()
        }
    }

    /// Send a recording command through the appropriate channel (direct or daemon).
    pub fn send_recording_command(&self, cmd: RecordingCommand) {
        if let Some(ref tx) = self.daemon_tx {
            let _ = tx.send(crate::ipc::ClientMessage::Recording(cmd));
        } else if let Some(ref tx) = self.recording_tx {
            let _ = tx.send(cmd);
        }
    }

    /// Request an immediate channel re-poll. Wired to F5. In daemon mode
    /// this travels over IPC; in standalone mode we notify the monitor's
    /// poll_notify handle directly.
    pub fn request_poll_now(&mut self) {
        if let Some(ref tx) = self.daemon_tx {
            match tx.send(crate::ipc::ClientMessage::PollNow) {
                Ok(()) => {
                    self.status_message = "Refreshing channels…".to_string();
                }
                Err(_) => {
                    self.status_message = "Refresh failed — daemon connection closed".to_string();
                }
            }
        } else if let Some(ref notify) = self.poll_notify_standalone {
            notify.notify_one();
            self.status_message = "Refreshing channels…".to_string();
        } else {
            self.status_message = "Refresh unavailable — no platforms authenticated".to_string();
        }
    }

    pub fn active_recording_count(&self) -> usize {
        self.recordings
            .values()
            .filter(|r| {
                r.state == RecordingState::Recording || r.state == RecordingState::ResolvingUrl
            })
            .count()
    }

    pub fn sorted_recordings(&self) -> Vec<&RecordingJob> {
        let mut recs: Vec<&RecordingJob> = self.recordings.values().collect();
        recs.sort_by_key(|r| std::cmp::Reverse(r.started_at));
        recs
    }

    /// Re-derive `selected_recording` from `selected_recording_id` after
    /// any mutation to `recordings`. If the tracked ID is gone (deletion,
    /// cleanup), the selection falls back to index 0 and the tracked ID
    /// is updated to whatever sits there. Call after any insert/remove.
    pub fn reconcile_selected_recording(&mut self) {
        let ids: Vec<Uuid> = self.sorted_recordings().iter().map(|r| r.id).collect();
        if ids.is_empty() {
            self.selected_recording = 0;
            self.selected_recording_id = None;
            return;
        }
        if let Some(id) = self.selected_recording_id {
            if let Some(idx) = ids.iter().position(|&i| i == id) {
                self.selected_recording = idx;
                return;
            }
        }
        // ID is gone (or never tracked) — clamp to the current top.
        let clamped = self.selected_recording.min(ids.len() - 1);
        self.selected_recording = clamped;
        self.selected_recording_id = ids.get(clamped).copied();
    }

    /// Update `selected_recording_id` to match the current index and
    /// persist it through TuiState. Call from key handlers that move
    /// the cursor.
    pub fn remember_recording_selection(&mut self) {
        let ids: Vec<Uuid> = self.sorted_recordings().iter().map(|r| r.id).collect();
        self.selected_recording_id = ids.get(self.selected_recording).copied();
        // Persist sparingly — only when the tracked ID actually changed.
        if self.state.selected_recording != self.selected_recording_id {
            self.state.selected_recording = self.selected_recording_id;
            self.state.save();
        }
    }

    /// Spawn a preview probe for the currently-selected recording, if
    /// one isn't already cached. Called from RecordingList nav helpers
    /// (yazi audit §6). Returns the AppAction the run loop should
    /// execute (ProbeMedia). The PreviewLock cancels any prior probe so
    /// rapid cursor movement doesn't pile up work.
    pub fn maybe_spawn_recording_preview(&mut self) -> Option<AppAction> {
        let recs = self.sorted_recordings();
        let rec = recs.get(self.selected_recording)?;
        let job_id = rec.id;
        if self.media_info_cache.contains_key(&job_id) {
            // Already cached — just refresh the lock key so a later
            // late-completion knows it's still relevant.
            let _ = self.preview.start(job_id.to_string());
            return None;
        }
        if rec.state != RecordingState::Finished {
            return None;
        }
        let path = rec.output_path.clone();
        let _ = self.preview.start(job_id.to_string());
        Some(AppAction::ProbeMedia { job_id, path })
    }

    /// Groups finished+active recordings by day label ("Today", "Yesterday", "March 12, 2026"), newest first
    pub fn recordings_by_day(&self) -> Vec<(String, Vec<&RecordingJob>)> {
        use chrono::Local;

        let mut recs = self.sorted_recordings();
        // sorted_recordings already sorts newest first
        if recs.is_empty() {
            return Vec::new();
        }

        let today = Local::now().date_naive();
        let yesterday = today - chrono::Duration::days(1);

        let mut groups: Vec<(String, Vec<&RecordingJob>)> = Vec::new();

        for rec in recs.drain(..) {
            let rec_date = rec.started_at.with_timezone(&Local).date_naive();
            let label = if rec_date == today {
                "Today".to_string()
            } else if rec_date == yesterday {
                "Yesterday".to_string()
            } else {
                rec_date.format("%B %-d, %Y").to_string()
            };

            if let Some(last) = groups.last_mut() {
                if last.0 == label {
                    last.1.push(rec);
                    continue;
                }
            }
            groups.push((label, vec![rec]));
        }

        groups
    }

    /// Counts finished recordings where `watched == false` for a given channel
    pub fn unwatched_count_for_channel(&self, channel_id: &str) -> usize {
        self.recordings
            .values()
            .filter(|r| {
                r.channel_id == channel_id && r.state == RecordingState::Finished && !r.watched
            })
            .count()
    }

    pub fn handle_event(&mut self, event: AppEvent) -> Option<AppAction> {
        match event {
            AppEvent::Key(key) => return self.handle_key(key),
            AppEvent::Resize(_, _) => {}
            AppEvent::Tick => {
                self.tick_counter = self.tick_counter.wrapping_add(1);
                // Reset scroll offset when selection changes
                if self.selected_channel != self.prev_selected_channel {
                    self.scroll_offsets.remove(&self.prev_selected_channel);
                    self.prev_selected_channel = self.selected_channel;
                }
                // Status message auto-dismiss (≈5 s after the last change)
                if self.status_message != self.prev_status_message {
                    self.prev_status_message = self.status_message.clone();
                    self.status_message_at = if self.status_message.is_empty() {
                        None
                    } else {
                        Some(std::time::Instant::now())
                    };
                } else if let Some(at) = self.status_message_at {
                    if at.elapsed().as_secs() >= 5 {
                        self.status_message.clear();
                        self.status_message_at = None;
                        self.prev_status_message.clear();
                    }
                }
                // Autoscroll stream title for selected live channel in sidebar
                if self.active_pane == ActivePane::Sidebar {
                    if let Some(ch) = self.channels.get(self.selected_channel) {
                        if ch.is_live && ch.stream_title.is_some()
                            && self.tick_counter % 6 == 0 {
                                let offset = self
                                    .scroll_offsets
                                    .entry(self.selected_channel)
                                    .or_insert(0);
                                *offset += 1;
                            }
                    }
                }
            }
            AppEvent::ThumbnailReady { channel_id, path } => {
                self.thumbnail_cache.insert(channel_id.clone(), path);
            }
            AppEvent::ThumbnailDecoded {
                channel_id,
                protocol,
            } => {
                self.thumbnail_changed_at
                    .insert(channel_id.clone(), std::time::Instant::now());
                self.thumbnail_protocols.insert(channel_id, protocol);
            }
            AppEvent::RecordingThumbnailDecoded { id, protocol } => {
                self.recording_thumb_in_flight.remove(&id);
                self.recording_thumb_protocols.insert(id, protocol);
            }
            AppEvent::WatchResolved {
                channel_name,
                stream_url,
            } => {
                self.watching_channel = Some(channel_name.clone());
                return Some(AppAction::LaunchMpv {
                    channel_name,
                    url: stream_url,
                });
            }
            AppEvent::WatchFailed { error } => {
                self.status_message = format!("Watch failed: {error}");
            }
            AppEvent::Daemon(de) => return self.handle_daemon_event(de),
            // PluginEvent is handled by the caller (tui::run_loop) which owns the registry
            AppEvent::PluginEvent { .. } => {}
            AppEvent::MediaProbed { job_id, info } => {
                self.media_info_cache.insert(job_id, info);
            }
            AppEvent::DaemonDisconnected => {
                if self.daemon_connected {
                    self.daemon_disconnected_at = Some(std::time::Instant::now());
                }
                self.daemon_connected = false;
                self.daemon_reconnect_attempts = self.daemon_reconnect_attempts.saturating_add(1);
                self.status_message = "⚠ Daemon disconnected — reconnecting…".to_string();
            }
            AppEvent::DaemonReconnected => {
                self.daemon_connected = true;
                self.daemon_reconnect_attempts = 0;
                self.daemon_disconnected_at = None;
                self.status_message = "✓ Daemon reconnected".to_string();
            }
            AppEvent::LogBridge(ev) => {
                if self.event_ring.len() >= EVENT_RING_CAP {
                    self.event_ring.pop_front();
                }
                self.event_ring.push_back(ev);
            }
        }
        None
    }

    /// Push a user-facing event onto the in-memory ring. Sized to
    /// EVENT_RING_CAP; oldest entries fall off the front.
    pub fn push_event(
        &mut self,
        level: UiEventLevel,
        source: &'static str,
        message: impl Into<String>,
    ) {
        if self.event_ring.len() >= EVENT_RING_CAP {
            self.event_ring.pop_front();
        }
        self.event_ring.push_back(UiEvent {
            at: chrono::Utc::now(),
            level,
            source,
            message: message.into(),
        });
    }

    pub fn handle_daemon_event(&mut self, event: DaemonEvent) -> Option<AppAction> {
        // Mirror the event into the user-facing ring before dispatch so
        // every variant lands there even when the handler is a no-op.
        let (level, message): (UiEventLevel, String) = match &event {
            DaemonEvent::ChannelWentLive(ch) => {
                (UiEventLevel::Info, format!("{} went live", ch.display_name))
            }
            DaemonEvent::ChannelWentOffline(ch) => (
                UiEventLevel::Info,
                format!("{} went offline", ch.display_name),
            ),
            DaemonEvent::RecordingStarted { job } => (
                UiEventLevel::Info,
                format!("Recording started: {}", job.channel_name),
            ),
            DaemonEvent::RecordingFinished {
                job_id,
                final_state,
                error,
            } => {
                let level = match final_state {
                    RecordingState::Finished => UiEventLevel::Info,
                    RecordingState::Failed => UiEventLevel::Warn,
                    _ => UiEventLevel::Info,
                };
                let msg = if let Some(e) = error {
                    format!("Recording {job_id} → {final_state}: {e}")
                } else {
                    format!("Recording {job_id} → {final_state}")
                };
                (level, msg)
            }
            DaemonEvent::ScheduleFired {
                channel,
                duration_secs,
                ..
            } => (
                UiEventLevel::Info,
                format!("Schedule fired: {channel} ({} min)", duration_secs / 60),
            ),
            DaemonEvent::PlatformAuthenticated { kind } => {
                (UiEventLevel::Info, format!("{kind} connected"))
            }
            DaemonEvent::Notification { title, body } => (
                UiEventLevel::Info,
                if body.is_empty() {
                    title.clone()
                } else {
                    format!("{title}: {body}")
                },
            ),
            DaemonEvent::Error(msg) => (UiEventLevel::Error, msg.clone()),
            _ => (UiEventLevel::Trace, String::new()),
        };
        if !message.is_empty() {
            self.push_event(level, "daemon", message);
        }

        match event {
            DaemonEvent::ChannelsUpdated(channels) => {
                // Remember currently selected channel by ID
                let prev_selected_id = self
                    .channels
                    .get(self.selected_channel)
                    .map(|ch| ch.id.clone());

                // Preserve auto_record settings from config
                let mut updated = channels;
                for ch in &mut updated {
                    ch.auto_record =
                        self.config.auto_record_channels.iter().any(|a| {
                            a.channel_id == ch.id && a.platform == ch.platform.to_string()
                        });
                }
                // The main monitor's ChannelsUpdated carries only the
                // live platforms (Twitch/YT). Patreon creators arrive
                // separately via PatreonState, so carry them across this
                // wholesale replace instead of dropping them every poll
                // (task #69).
                let patreon_rows: Vec<ChannelEntry> = self
                    .channels
                    .iter()
                    .filter(|c| c.platform == PlatformKind::Patreon)
                    .cloned()
                    .collect();
                updated.extend(patreon_rows);
                self.channels = updated;

                // Restore selection by ID, fall back to clamping
                if let Some(ref prev_id) = prev_selected_id {
                    if let Some(new_idx) = self.channels.iter().position(|ch| &ch.id == prev_id) {
                        self.selected_channel = new_idx;
                    } else if self.selected_channel >= self.channels.len() {
                        self.selected_channel = self.channels.len().saturating_sub(1);
                    }
                } else if self.selected_channel >= self.channels.len() {
                    self.selected_channel = self.channels.len().saturating_sub(1);
                }

                // Prune stale thumbnail entries
                let current_ids: HashSet<String> =
                    self.channels.iter().map(|ch| ch.id.clone()).collect();
                self.thumbnail_cache
                    .retain(|id, _| current_ids.contains(id));
                self.thumbnail_protocols
                    .retain(|id, _| current_ids.contains(id));

                self.rebuild_sidebar_order();
            }
            DaemonEvent::ChannelWentLive(ref channel) => {
                self.status_message = format!("{} went live!", channel.display_name);
                return Some(AppAction::Notify {
                    title: format!("{} is live!", channel.display_name),
                    body: channel
                        .stream_title
                        .clone()
                        .unwrap_or_else(|| "Stream started".to_string()),
                });
            }
            DaemonEvent::ChannelWentOffline(channel) => {
                self.status_message = format!("{} went offline", channel.display_name);
            }
            DaemonEvent::StreamUrlResolved { channel_id, .. } => {
                self.status_message = format!("Stream URL resolved for {channel_id}");
            }
            DaemonEvent::RecordingStarted { mut job } => {
                if self.state.watched.contains(&job.id) {
                    job.watched = true;
                }
                self.status_message = format!("Recording started: {}", job.channel_name);
                // Register a Record task so the status-bar tail and the
                // future tasks pane reflect ongoing work.
                let task_id = self.tasks.start(
                    crate::tasks::TaskKind::Record,
                    job.channel_name.clone(),
                    tokio_util::sync::CancellationToken::new(),
                );
                self.task_by_recording.insert(job.id, task_id);
                self.recordings.insert(job.id, job);
                self.rebuild_active_channels();
                self.rebuild_sidebar_order();
                self.reconcile_selected_recording();
            }
            DaemonEvent::RecordingProgress {
                job_id,
                bytes_written,
                duration_secs,
            } => {
                if let Some(job) = self.recordings.get_mut(&job_id) {
                    job.bytes_written = bytes_written;
                    job.duration_secs = duration_secs;
                    job.state = RecordingState::Recording;
                }
                // Mirror progress onto the task entry so the status-bar
                // tail surfaces "rec 1.2 GB" without polling.
                if let Some(&task_id) = self.task_by_recording.get(&job_id) {
                    self.tasks.set_progress(
                        task_id,
                        crate::tasks::Progress::Bytes {
                            done: bytes_written,
                            total: None,
                        },
                    );
                }
            }
            DaemonEvent::RecordingFinished {
                job_id,
                final_state,
                error,
            } => {
                if let Some(job) = self.recordings.get_mut(&job_id) {
                    job.state = final_state;
                    job.error = error.clone();
                }
                if let Some(task_id) = self.task_by_recording.remove(&job_id) {
                    match final_state {
                        RecordingState::Finished => self.tasks.complete(task_id),
                        _ => {
                            let err = error
                                .clone()
                                .unwrap_or_else(|| format!("ended in state {final_state:?}"));
                            self.tasks.fail(task_id, err);
                        }
                    }
                }
                self.rebuild_active_channels();
                self.rebuild_sidebar_order();
                // Selection list is sorted by started_at so finishes don't
                // reorder, but recording UUIDs that get removed elsewhere
                // (e.g. future M1.3.b delete-to-trash) would; keep the
                // index in sync regardless.
                self.reconcile_selected_recording();
                let active = self.active_recording_count();
                self.status_message = format!("Recording finished ({active} active)");
                // M4.6: surface finished recordings as desktop
                // notifications so users running the daemon in the
                // background still see completion.
                let finished_label = self
                    .recordings
                    .get(&job_id)
                    .map(|j| j.channel_name.clone())
                    .unwrap_or_else(|| job_id.to_string());
                return Some(AppAction::Notify {
                    title: match final_state {
                        RecordingState::Finished => "Recording finished".into(),
                        RecordingState::Failed => "Recording failed".into(),
                        _ => "Recording ended".into(),
                    },
                    body: finished_label,
                });
            }
            DaemonEvent::Notification { title, body } => {
                return Some(AppAction::Notify { title, body });
            }
            DaemonEvent::AllRecordingsStopped => {
                self.should_quit = true;
            }
            DaemonEvent::DeviceCodeRequired {
                kind,
                verification_uri,
                user_code,
            } => {
                self.status_message =
                    format!("{kind} auth: go to {verification_uri} and enter code: {user_code}");
                let entry = (kind, verification_uri, user_code);
                // Deduplicate: a re-fire for the same platform replaces the
                // previous code rather than stacking.
                if matches!(&self.pending_auth, Some((p, _, _)) if *p == entry.0) {
                    self.pending_auth = Some(entry);
                } else {
                    self.auth_queue.retain(|(p, _, _)| *p != entry.0);
                    if self.pending_auth.is_none() {
                        self.pending_auth = Some(entry);
                    } else {
                        self.auth_queue.push_back(entry);
                    }
                }
            }
            DaemonEvent::PlatformAuthenticated { kind } => {
                match kind {
                    PlatformKind::Twitch => self.twitch_connected = true,
                    PlatformKind::YouTube => self.youtube_connected = true,
                    PlatformKind::Patreon => self.patreon_connected = true,
                }
                self.status_message = format!("{kind} connected");
                if matches!(&self.pending_auth, Some((pending, _, _)) if *pending == kind) {
                    self.pending_auth = self.auth_queue.pop_front();
                }
                self.auth_queue.retain(|(p, _, _)| *p != kind);
            }
            DaemonEvent::PatreonPostFound {
                creator_name,
                post_title,
            } => {
                self.status_message = format!("Patreon: {creator_name} posted '{post_title}'");
            }
            DaemonEvent::BulkProgress {
                channel_id,
                done,
                total,
                active,
            } => {
                if active {
                    self.bulk_downloads.insert(
                        channel_id,
                        BulkDlStatus { done, total, active },
                    );
                } else {
                    // Completed/cancelled — drop the row so the sidebar
                    // indicator clears.
                    self.bulk_downloads.remove(&channel_id);
                }
            }
            DaemonEvent::PlaylistList {
                channel_id,
                playlists,
            } => {
                // Fill the open picker if it's for this channel.
                if let Some(picker) = self.playlist_picker.as_mut() {
                    if picker.channel_id == channel_id {
                        picker.playlists = playlists;
                        picker.loading = false;
                    }
                }
            }
            // Webui-only: the TUI shows channel VODs via its own panes.
            DaemonEvent::ChannelVods { .. } => {}
            // Add-Channel wizard is webui-only; the TUI ignores resolve replies.
            DaemonEvent::ChannelResolved { .. } => {}
            DaemonEvent::PatreonState { creators, posts } => {
                // Cache posts by campaign_id, newest first.
                let mut by_campaign: HashMap<String, Vec<crate::platform::patreon::PatreonPost>> =
                    HashMap::new();
                for post in posts {
                    by_campaign
                        .entry(post.campaign_id.clone())
                        .or_default()
                        .push(post);
                }
                for list in by_campaign.values_mut() {
                    list.sort_by(|a, b| b.published_at.cmp(&a.published_at));
                }
                self.patreon_posts = by_campaign;

                // Replace the Patreon rows in the sidebar, preserving the
                // current selection by id. Non-Patreon rows are untouched.
                let prev_selected_id = self
                    .channels
                    .get(self.selected_channel)
                    .map(|ch| ch.id.clone());
                self.channels
                    .retain(|c| c.platform != PlatformKind::Patreon);
                self.channels.extend(creators);
                if let Some(ref prev_id) = prev_selected_id {
                    if let Some(idx) = self.channels.iter().position(|c| &c.id == prev_id) {
                        self.selected_channel = idx;
                    }
                }
                if self.selected_channel >= self.channels.len() {
                    self.selected_channel = self.channels.len().saturating_sub(1);
                }
                self.rebuild_sidebar_order();
            }
            DaemonEvent::ScheduleFired {
                channel,
                duration_secs,
                ..
            } => {
                let mins = duration_secs / 60;
                self.status_message = format!("Schedule fired: {channel} ({mins} min)");
                return Some(AppAction::Notify {
                    title: "Scheduled recording".into(),
                    body: format!("{channel} — {mins} min"),
                });
            }
            DaemonEvent::Error(ref msg) => {
                self.status_message = format!("Error: {msg}");
                // Categorize error by platform keywords for the diagnostics view
                let msg_lower = msg.to_lowercase();
                let kind = if msg_lower.contains("twitch") || msg_lower.contains("streamlink") {
                    Some(PlatformKind::Twitch)
                } else if msg_lower.contains("youtube")
                    || msg_lower.contains("yt-dlp")
                    || msg_lower.contains("ytdlp")
                {
                    Some(PlatformKind::YouTube)
                } else if msg_lower.contains("patreon") {
                    Some(PlatformKind::Patreon)
                } else {
                    None
                };
                if let Some(kind) = kind {
                    let errors = self.platform_errors.entry(kind).or_default();
                    errors.push(msg.clone());
                    if errors.len() > 10 {
                        errors.remove(0);
                    }
                }
            }
        }
        None
    }

    /// Open the text-input modal with a given purpose, prompt, and initial value.
    pub fn open_text_input(
        &mut self,
        purpose: crate::tui::widgets::text_input::TextInputPurpose,
        prompt: impl Into<String>,
        initial: impl Into<String>,
    ) {
        self.text_input = Some(crate::tui::widgets::text_input::TextInputState::new(
            purpose, prompt, initial,
        ));
    }

    /// Drain `text_input` and act on it by purpose.
    fn commit_text_input(&mut self) {
        use crate::tui::widgets::text_input::TextInputPurpose as P;
        let Some(state) = self.text_input.take() else {
            return;
        };
        let value = state.value;
        match state.purpose {
            P::RenameRecording { job_id } => {
                let Some(job) = self.recordings.get(&job_id).cloned() else {
                    self.status_message = "Recording vanished before rename".into();
                    return;
                };
                let old = job.output_path.clone();
                let Some(parent) = old.parent() else {
                    self.status_message = "Recording has no parent dir".into();
                    return;
                };
                // Preserve extension on rename if user didn't supply one.
                let new_name = if std::path::Path::new(&value).extension().is_some() {
                    value
                } else {
                    let ext = old.extension().and_then(|s| s.to_str()).unwrap_or("mkv");
                    format!("{value}.{ext}")
                };
                let new = parent.join(&new_name);
                if new.exists() {
                    self.status_message = format!("Target already exists: {}", new.display());
                    return;
                }
                match std::fs::rename(&old, &new) {
                    Ok(()) => {
                        if let Some(job) = self.recordings.get_mut(&job_id) {
                            job.output_path = new.clone();
                        }
                        self.status_message = format!("Renamed to {}", new_name);
                    }
                    Err(e) => self.status_message = format!("Rename failed: {e}"),
                }
            }
            P::MoveRecording { job_id } => {
                let Some(job) = self.recordings.get(&job_id).cloned() else {
                    self.status_message = "Recording vanished before move".into();
                    return;
                };
                let dest_dir = std::path::PathBuf::from(shellexpand(&value));
                if !dest_dir.exists() {
                    if let Err(e) = std::fs::create_dir_all(&dest_dir) {
                        self.status_message = format!("Create dest failed: {e}");
                        return;
                    }
                }
                let file_name = job.output_path.file_name().unwrap_or_default();
                let dest = dest_dir.join(file_name);
                if dest.exists() {
                    self.status_message = format!("Target already exists: {}", dest.display());
                    return;
                }
                match std::fs::rename(&job.output_path, &dest) {
                    Ok(()) => {
                        if let Some(job) = self.recordings.get_mut(&job_id) {
                            job.output_path = dest.clone();
                        }
                        self.status_message = format!("Moved to {}", dest.display());
                    }
                    Err(e) => self.status_message = format!("Move failed: {e}"),
                }
            }
            P::ScheduleAddChannel => {
                // First step: take channel, ask for cron next.
                self.open_text_input(
                    P::ScheduleAddCron { channel: value },
                    "Cron expression (5-field, e.g. `0 20 * * 1-5`)",
                    "0 20 * * 1-5",
                );
            }
            P::ScheduleAddCron { channel } => {
                self.open_text_input(
                    P::ScheduleAddDuration {
                        channel,
                        cron: value,
                    },
                    "Duration (e.g. `4h`, `90m`, `2h30m`)",
                    "4h",
                );
            }
            P::ScheduleAddDuration { channel, cron } => {
                self.config.schedule.push(crate::config::ScheduleEntry {
                    channel,
                    cron,
                    duration: value,
                });
                if let Err(e) = self.config.save(None) {
                    self.status_message = format!("Add schedule: save failed: {e}");
                } else {
                    self.status_message = "Schedule added".into();
                }
            }
            P::ScheduleEditCron { index } => {
                if let Some(entry) = self.config.schedule.get_mut(index) {
                    entry.cron = value;
                    if let Err(e) = self.config.save(None) {
                        self.status_message = format!("Edit schedule: save failed: {e}");
                    } else {
                        self.status_message = "Schedule cron updated".into();
                    }
                }
            }
            P::ScheduleEditDuration { index } => {
                if let Some(entry) = self.config.schedule.get_mut(index) {
                    entry.duration = value;
                    if let Err(e) = self.config.save(None) {
                        self.status_message = format!("Edit schedule: save failed: {e}");
                    } else {
                        self.status_message = "Schedule duration updated".into();
                    }
                }
            }
            P::SettingsString { key } => self.apply_settings_string(key, value),
            P::SettingsInt { key } => self.apply_settings_int(key, &value),
            P::SettingsPath { key } => {
                let expanded = shellexpand(&value);
                self.apply_settings_string(key, expanded);
            }
            P::CommandPalette => {
                let trimmed = value.trim();
                if let Some(action) = crate::tui::keymap::KeyAction::from_name(trimmed) {
                    let _ = self.apply_key_action(action);
                    self.status_message = format!("→ {trimmed}");
                } else {
                    self.status_message = format!("unknown command: {trimmed}");
                }
            }
            P::SetMark => {
                let Some(c) = value.chars().next() else {
                    return;
                };
                if !c.is_ascii_lowercase() {
                    self.status_message = "marks must be lowercase a-z".into();
                    return;
                }
                if let Some(ch) = self.selected_channel() {
                    let id = ch.id.clone();
                    let display = ch.display_name.clone();
                    self.state.marks.insert(c, id);
                    self.state.save();
                    self.status_message = format!("mark '{c}' = {display}");
                }
            }
            P::JumpMark => {
                let Some(c) = value.chars().next() else {
                    return;
                };
                let Some(channel_id) = self.state.marks.get(&c).cloned() else {
                    self.status_message = format!("no mark '{c}'");
                    return;
                };
                if let Some(idx) = self.channels.iter().position(|ch| ch.id == channel_id) {
                    self.selected_channel = idx;
                    self.active_pane = ActivePane::Sidebar;
                    self.status_message = format!("jumped to mark '{c}'");
                } else {
                    self.status_message = format!("mark '{c}' points at a stale channel");
                }
            }
            P::PaletteSavePreset => {
                let name = value.trim();
                if name.is_empty() {
                    self.status_message = "preset name required".into();
                    return;
                }
                match crate::edl::recorder::save(name, &self.command_log) {
                    Ok(path) => {
                        self.status_message = format!(
                            "saved preset '{name}' ({} actions) → {}",
                            self.command_log.len(),
                            path.display()
                        );
                    }
                    Err(e) => {
                        self.status_message = format!("save-preset failed: {e}");
                    }
                }
            }
        }
    }

    /// Routes a committed string from the settings text-input modal to
    /// the right config field. Saving is immediate so the file stays
    /// in sync with the rendered value.
    fn apply_settings_string(&mut self, key: &'static str, value: String) {
        match key {
            "recording_dir" => self.config.recording_dir = std::path::PathBuf::from(value),
            "filename_template" => self.config.recording.filename_template = value,
            "recording.format.format" => {
                self.config.recording.format.format =
                    if value.is_empty() { None } else { Some(value) };
            }
            "archiver.archive_dir" => {
                self.config.archiver.archive_dir = std::path::PathBuf::from(value);
            }
            "archiver.format" => self.config.archiver.format = value,
            "archiver.rate_limit" => self.config.archiver.rate_limit = value,
            "crunchr.whisper_model" => {
                self.config.crunchr.whisper_model =
                    if value.is_empty() { None } else { Some(value) };
            }
            "crunchr.analysis.model" => self.config.crunchr.analysis.model = value,
            _ => {
                self.status_message = format!("unknown string setting: {key}");
                return;
            }
        }
        if let Err(e) = self.config.save(None) {
            self.status_message = format!("Save failed: {e}");
        } else {
            self.status_message = format!("{key} updated");
        }
    }

    /// Routes a committed integer string. Reports a parse error back
    /// into the modal so the user can fix it without retyping.
    fn apply_settings_int(&mut self, key: &'static str, raw: &str) {
        let Ok(n) = raw.parse::<u64>() else {
            // Re-open with the same value plus an error message.
            if let Some(ref mut st) = self.text_input {
                st.error = Some(format!("'{raw}' is not a positive integer"));
                self.text_input.as_mut().unwrap().value = raw.to_string();
                self.text_input.as_mut().unwrap().cursor = raw.chars().count();
            }
            return;
        };
        match key {
            "poll_interval_secs" => self.config.poll_interval_secs = n.max(15),
            "crunchr.whisper_timeout_secs" => self.config.crunchr.whisper_timeout_secs = n,
            "archiver.concurrent_fragments" => {
                self.config.archiver.concurrent_fragments = n.clamp(1, 16) as u32;
            }
            "recording.format.bitrate_kbps" => {
                self.config.recording.format.bitrate_kbps =
                    if n == 0 { None } else { Some(n as u32) };
            }
            _ => {
                self.status_message = format!("unknown int setting: {key}");
                return;
            }
        }
        if let Err(e) = self.config.save(None) {
            self.status_message = format!("Save failed: {e}");
        } else {
            self.status_message = format!("{key} updated");
        }
    }

    /// Translate a typed [`crate::tui::keymap::KeyAction`] into a state
    /// mutation (or an [`AppAction`] for the TUI loop). Single source of
    /// truth for what a global key does — when migrating per-pane keys
    /// into the table (M3 follow-ups), variants land here.
    fn apply_key_action(&mut self, action: crate::tui::keymap::KeyAction) -> Option<AppAction> {
        use crate::tui::keymap::KeyAction as A;
        match action {
            A::Quit if self.active_pane != ActivePane::Wizard => {
                if self.active_recording_count() > 0 {
                    self.quit_confirm = true;
                    self.status_message = "Recordings active! Quit? (y/n)".to_string();
                } else {
                    self.should_quit = true;
                }
                None
            }
            A::Quit => None,
            A::HelpToggle => {
                self.show_help = !self.show_help;
                None
            }
            A::HelpClose => {
                self.show_help = false;
                None
            }
            A::ThemePickerOpen => {
                self.open_theme_picker();
                None
            }
            A::EventLogToggle => {
                self.show_event_log = !self.show_event_log;
                self.event_log_scroll = 0;
                None
            }
            A::PluginBrowserToggle => {
                self.show_plugin_browser = !self.show_plugin_browser;
                None
            }
            A::EnterStatusBar => {
                if self.active_pane != ActivePane::StatusBar {
                    self.prev_pane = Some(self.active_pane.clone());
                    self.active_pane = ActivePane::StatusBar;
                    self.selected_indicator = 0;
                }
                None
            }
            A::EnterLogPane
                if self.active_pane != ActivePane::Wizard
                    && self.active_pane != ActivePane::Log =>
            {
                self.clear_search();
                self.refresh_log();
                self.active_pane = ActivePane::Log;
                None
            }
            A::EnterLogPane => None,
            A::EnterSchedulePane
                if self.active_pane != ActivePane::Wizard
                    && self.active_pane != ActivePane::Schedule =>
            {
                self.clear_search();
                self.active_pane = ActivePane::Schedule;
                self.selected_schedule = self
                    .selected_schedule
                    .min(self.config.schedule.len().saturating_sub(1));
                None
            }
            A::EnterSchedulePane => None,
            A::SearchStart
                if matches!(
                    self.active_pane,
                    ActivePane::Sidebar | ActivePane::RecordingList | ActivePane::Detail
                ) =>
            {
                self.search_active = true;
                self.search_query.clear();
                self.search_cursor = 0;
                self.search_filtered_channels.clear();
                self.search_filtered_recordings.clear();
                None
            }
            A::SearchStart => None,
            A::PluginActivate => None,
            A::CommandPaletteOpen => {
                // D4 — open the fuzzy command palette overlay. Old
                // text-input-based stub stays for back-compat (any
                // caller using `open_text_input(CommandPalette, …)`
                // still works) but the `:` key now lands on the proper
                // modal.
                self.palette = Some(PaletteState::default());
                None
            }
            A::DagOverlayToggle => {
                self.show_dag_overlay = !self.show_dag_overlay;
                if !self.show_dag_overlay {
                    self.dag_overlay_opened_at = None;
                }
                None
            }
            A::ActionsPopupOpen => {
                // D5 — open the verb menu scoped to the focused item.
                // Today we only register entries for the RecordingList
                // pane; once `PluginCommand::Scope::Item` lands the
                // entry list grows per active context.
                if matches!(self.active_pane, ActivePane::RecordingList) {
                    // We don't have the plugin registry handle here
                    // (apply_key_action is called outside the render
                    // path). Wire built-ins; plugin-contributed verbs
                    // are merged in just before render — see the
                    // hydrate_plugin_verbs() call in the render loop.
                    let entries = crate::tui::widgets::actions_popup::entries_for_recording_list_builtins();
                    self.actions_popup = Some(ActionsPopupState {
                        entries,
                        selected: 0,
                    });
                }
                None
            }
            A::MarkSetPrompt => {
                self.open_text_input(
                    crate::tui::widgets::text_input::TextInputPurpose::SetMark,
                    "Set mark (single lowercase letter)",
                    "",
                );
                None
            }
            A::MarkJumpPrompt => {
                self.open_text_input(
                    crate::tui::widgets::text_input::TextInputPurpose::JumpMark,
                    "Jump to mark (single lowercase letter)",
                    "",
                );
                None
            }
            A::CopyToClipboard => {
                let target: Option<String> = match self.active_pane {
                    ActivePane::Detail => self.selected_channel().map(|ch| match ch.platform {
                        PlatformKind::Twitch => format!("https://twitch.tv/{}", ch.name),
                        PlatformKind::YouTube => {
                            if ch.id.starts_with("UC") {
                                format!("https://youtube.com/channel/{}", ch.id)
                            } else {
                                format!("https://youtube.com/@{}", ch.name)
                            }
                        }
                        PlatformKind::Patreon => format!("https://patreon.com/{}", ch.name),
                    }),
                    ActivePane::RecordingList => {
                        let recs = self.sorted_recordings();
                        recs.get(self.selected_recording)
                            .map(|r| r.output_path.display().to_string())
                    }
                    _ => None,
                };
                if let Some(text) = target {
                    match crate::tui::clipboard::copy(&text) {
                        Ok(via) => self.status_message = format!("copied via {via}"),
                        Err(e) => self.status_message = format!("copy failed: {e}"),
                    }
                }
                None
            }
            A::OpenInFolder => {
                if matches!(self.active_pane, ActivePane::RecordingList) {
                    let recs = self.sorted_recordings();
                    if let Some(rec) = recs.get(self.selected_recording) {
                        if let Some(parent) = rec.output_path.parent() {
                            let url = format!("file://{}", parent.display());
                            return Some(AppAction::OpenUrl { url });
                        }
                    }
                }
                None
            }
            A::VisualModeToggle => {
                self.input_mode = match self.input_mode {
                    InputMode::Visual => InputMode::Normal,
                    _ => {
                        // Entering visual mode seeds the selection with
                        // the current row so a Shift+V → D flow is a
                        // single-row delete-to-trash without prior `v`.
                        if matches!(self.active_pane, ActivePane::RecordingList) {
                            self.recording_list_extend_selection();
                        }
                        InputMode::Visual
                    }
                };
                None
            }
            A::EnterSettings => {
                self.active_pane = ActivePane::Settings;
                None
            }
            A::EnterRecordingList => {
                self.active_pane = ActivePane::RecordingList;
                None
            }
            A::NavDown => {
                self.pane_nav_down();
                if matches!(self.active_pane, ActivePane::RecordingList) {
                    return self.maybe_spawn_recording_preview();
                }
                None
            }
            A::NavUp => {
                self.pane_nav_up();
                if matches!(self.active_pane, ActivePane::RecordingList) {
                    return self.maybe_spawn_recording_preview();
                }
                None
            }
            A::NavTop => {
                self.pane_nav_top();
                if matches!(self.active_pane, ActivePane::RecordingList) {
                    return self.maybe_spawn_recording_preview();
                }
                None
            }
            A::NavBottom => {
                self.pane_nav_bottom();
                if matches!(self.active_pane, ActivePane::RecordingList) {
                    return self.maybe_spawn_recording_preview();
                }
                None
            }
            A::NavBack => {
                self.pane_nav_back();
                None
            }
            A::NavActivate => self.pane_nav_activate(),
            A::ToggleAutoRecord => {
                self.toggle_auto_record_on_selected();
                None
            }
            A::ToggleBulkDownload => {
                self.toggle_bulk_download_on_selected();
                None
            }
            A::ToggleBulkDownloadPlatform => {
                self.toggle_bulk_download_platform();
                None
            }
            A::PickBulkPlaylist => {
                self.open_playlist_picker();
                None
            }
            // Default action records from the start of the stream:
            // YouTube via yt-dlp --live-from-start, Twitch via ffmpeg
            // -live_start_index 0 (~5min DVR window).
            A::StartRecording => self.start_recording_on_selected(true),
            A::StartRecordingFromStart => self.start_recording_on_selected(true),
            A::WatchStream => self.watch_selected_stream(),
            A::ToggleTranscode => {
                self.transcode_mode = !self.transcode_mode;
                self.config.recording.transcode = self.transcode_mode;
                let _ = self.config.save(None);
                self.status_message = if self.transcode_mode {
                    "Transcode mode: ON".into()
                } else {
                    "Transcode mode: OFF".into()
                };
                None
            }
            A::StopRecording => self.recording_list_stop_selected(),
            A::PlayRecording => self.recording_list_play_selected(),
            A::ShowRecordingProperties => self.recording_list_open_props(),
            A::ToggleRecordingSelect => {
                self.recording_list_toggle_select();
                None
            }
            A::ClearRecordingSelections => {
                self.recording_selections_order.clear();
                self.recording_selections_set.clear();
                None
            }
            A::TrashSelectedRecordings => {
                self.recording_list_trash_selected();
                None
            }
            A::RenameRecording => {
                self.recording_list_open_rename();
                None
            }
            A::MoveRecording => {
                self.recording_list_open_move();
                None
            }
            A::PlaybackTogglePause => {
                if self.playback.is_some() {
                    if let Some(ref mut st) = self.playback {
                        st.is_paused = !st.is_paused;
                    }
                    Some(AppAction::MpvTogglePause)
                } else {
                    None
                }
            }
            A::PlaybackSeekForward => {
                if self.playback.is_some() {
                    Some(AppAction::MpvSeek(10.0))
                } else {
                    None
                }
            }
            A::PlaybackSeekBack => {
                if self.playback.is_some() {
                    Some(AppAction::MpvSeek(-10.0))
                } else {
                    None
                }
            }
            A::PlaybackSpeedUp => {
                if let Some(ref mut st) = self.playback {
                    st.speed = (st.speed + 0.25).min(4.0);
                    Some(AppAction::MpvSetSpeed(st.speed))
                } else {
                    None
                }
            }
            A::PlaybackSpeedDown => {
                if let Some(ref mut st) = self.playback {
                    st.speed = (st.speed - 0.25).max(0.25);
                    Some(AppAction::MpvSetSpeed(st.speed))
                } else {
                    None
                }
            }
            A::PlaybackVolumeUp => {
                if let Some(ref mut st) = self.playback {
                    st.volume = (st.volume + 5).min(150);
                    Some(AppAction::MpvSetVolume(st.volume))
                } else {
                    None
                }
            }
            A::PlaybackVolumeDown => {
                if let Some(ref mut st) = self.playback {
                    st.volume = st.volume.saturating_sub(5);
                    Some(AppAction::MpvSetVolume(st.volume))
                } else {
                    None
                }
            }
            A::ScheduleAdd => {
                self.open_text_input(
                    crate::tui::widgets::text_input::TextInputPurpose::ScheduleAddChannel,
                    "Channel (e.g. `twitch:shroud`)",
                    "twitch:",
                );
                None
            }
            A::ScheduleEditCron => {
                if let Some(entry) = self.config.schedule.get(self.selected_schedule) {
                    let index = self.selected_schedule;
                    let cron = entry.cron.clone();
                    self.open_text_input(
                        crate::tui::widgets::text_input::TextInputPurpose::ScheduleEditCron {
                            index,
                        },
                        "Edit cron expression",
                        cron,
                    );
                }
                None
            }
            A::ScheduleEditDuration => {
                if let Some(entry) = self.config.schedule.get(self.selected_schedule) {
                    let index = self.selected_schedule;
                    let duration = entry.duration.clone();
                    self.open_text_input(
                        crate::tui::widgets::text_input::TextInputPurpose::ScheduleEditDuration {
                            index,
                        },
                        "Edit duration",
                        duration,
                    );
                }
                None
            }
            A::ScheduleDelete => {
                self.schedule_delete_selected();
                None
            }
            A::LogScrollPageDown => {
                self.log_scroll =
                    (self.log_scroll + 30).min(self.log_lines.len().saturating_sub(1));
                self.log_auto_scroll = false;
                None
            }
            A::LogScrollPageUp => {
                self.log_scroll = self.log_scroll.saturating_sub(30);
                self.log_auto_scroll = false;
                None
            }
            A::LogClear => {
                let _ = std::fs::write(&self.log_path, "");
                self.log_lines.clear();
                self.log_scroll = 0;
                self.status_message = "Log cleared".into();
                None
            }
            A::UndoLast => {
                self.undo_last();
                None
            }
            A::ToggleRecordingListView => {
                self.recording_list_view = match self.recording_list_view {
                    RecordingListView::List => RecordingListView::Grid,
                    RecordingListView::Grid => RecordingListView::List,
                };
                None
            }
        }
    }

    fn handle_key(&mut self, key: crossterm::event::KeyEvent) -> Option<AppAction> {
        use crossterm::event::{KeyCode, KeyEventKind};

        if key.kind != KeyEventKind::Press {
            return None;
        }

        // C5.2 — remember the last character keypress so the status-bar
        // hotkey it corresponds to can shimmer briefly.
        if let KeyCode::Char(c) = key.code {
            self.last_hotkey = Some(c);
            self.last_hotkey_at = Some(std::time::Instant::now());
        }

        // Text-input modal owns the keyboard while open. Dispatched
        // before search/quit/themepicker so callers can layer this on
        // top of any other state.
        if self.text_input.is_some() {
            let result = self
                .text_input
                .as_mut()
                .map(|st| st.handle_key(&key))
                .unwrap_or(crate::tui::widgets::text_input::TextInputResult::Idle);
            match result {
                crate::tui::widgets::text_input::TextInputResult::Cancel => {
                    self.text_input = None;
                }
                crate::tui::widgets::text_input::TextInputResult::Commit => {
                    self.commit_text_input();
                }
                crate::tui::widgets::text_input::TextInputResult::Idle => {}
            }
            return None;
        }

        // Search mode input handling — intercept all keys
        if self.search_active {
            match key.code {
                KeyCode::Esc => {
                    self.clear_search();
                }
                KeyCode::Enter => {
                    // Confirm filter and exit search input mode (filter stays active)
                    self.search_active = false;
                    if self.search_query.is_empty() {
                        self.clear_search();
                    }
                }
                KeyCode::Backspace
                    if self.search_cursor > 0 => {
                        let chars: Vec<char> = self.search_query.chars().collect();
                        let new_cursor = self.search_cursor - 1;
                        self.search_query = chars
                            .iter()
                            .enumerate()
                            .filter(|(i, _)| *i != new_cursor)
                            .map(|(_, c)| *c)
                            .collect();
                        self.search_cursor = new_cursor;
                        self.update_search_filter();
                    }
                KeyCode::Delete => {
                    let chars: Vec<char> = self.search_query.chars().collect();
                    if self.search_cursor < chars.len() {
                        self.search_query = chars
                            .iter()
                            .enumerate()
                            .filter(|(i, _)| *i != self.search_cursor)
                            .map(|(_, c)| *c)
                            .collect();
                        self.update_search_filter();
                    }
                }
                KeyCode::Left => {
                    self.search_cursor = self.search_cursor.saturating_sub(1);
                }
                KeyCode::Right => {
                    let len = self.search_query.chars().count();
                    if self.search_cursor < len {
                        self.search_cursor += 1;
                    }
                }
                KeyCode::Home => {
                    self.search_cursor = 0;
                }
                KeyCode::End => {
                    self.search_cursor = self.search_query.chars().count();
                }
                KeyCode::Char(c) => {
                    let mut chars: Vec<char> = self.search_query.chars().collect();
                    chars.insert(self.search_cursor, c);
                    self.search_query = chars.iter().collect();
                    self.search_cursor += 1;
                    self.update_search_filter();
                }
                _ => {}
            }
            return None;
        }

        // Wizard overlay owns `o` while a device-code flow is live, even if
        // the user is on another pane. Everything else falls through so the
        // underlying pane keeps behaving normally.
        if self.pending_auth.is_some() && self.active_pane != ActivePane::Wizard {
            if let KeyCode::Char('o') | KeyCode::Char('O') = key.code {
                if let Some((_, ref uri, _)) = self.pending_auth {
                    let url = uri.clone();
                    self.status_message = format!("Opening {url}…");
                    return Some(AppAction::OpenUrl { url });
                }
            }
        }

        // Quit confirmation handling
        if self.quit_confirm {
            match key.code {
                KeyCode::Char('y') | KeyCode::Char('Y') => {
                    // Stop all recordings — quit will happen when AllRecordingsStopped arrives
                    self.send_recording_command(RecordingCommand::StopAll);
                    self.status_message = "Stopping recordings...".to_string();
                    self.quit_confirm = false;
                    return None;
                }
                KeyCode::Char('n') | KeyCode::Char('N') | KeyCode::Esc => {
                    self.quit_confirm = false;
                    self.status_message.clear();
                    return None;
                }
                _ => return None,
            }
        }

        // Theme picker overlay — swallows all keys while open.
        if self.theme_picker.is_some() {
            self.handle_theme_picker_key(key);
            return None;
        }

        // Modal overlay dismiss (before global/pane keys)
        if self.show_platform_debug.is_some() {
            if matches!(key.code, KeyCode::Esc | KeyCode::Enter) {
                self.show_platform_debug = None;
            }
            return None;
        }

        if self.show_properties.is_some() {
            if matches!(key.code, KeyCode::Esc | KeyCode::Char('i')) {
                self.show_properties = None;
            }
            return None;
        }

        // Help-overlay-only dismiss key (Esc) is handled out-of-band:
        // the table dispatches on action codes, not modal toggles.
        if self.show_help && matches!(key.code, KeyCode::Esc) {
            self.show_help = false;
            return None;
        }
        if self.show_plugin_browser && matches!(key.code, KeyCode::Esc) {
            self.show_plugin_browser = false;
            return None;
        }

        if self.show_dag_overlay && matches!(key.code, KeyCode::Esc) {
            self.show_dag_overlay = false;
            return None;
        }

        // Command palette swallows everything except the dispatch keys
        // while open. Routing is local because the palette is a
        // soft-modal: arrow keys move the result selection, typing
        // characters extends the query, Enter dispatches, Esc closes.
        if self.palette.is_some() {
            return self.handle_palette_key(key);
        }

        // Actions popup — similar pattern, much smaller surface.
        if self.actions_popup.is_some() {
            return self.handle_actions_popup_key(key);
        }

        // Event-log overlay swallows its scroll keys before the table.
        // Esc closes; arrow keys + j/k/g/G adjust scroll.
        if self.show_event_log {
            match key.code {
                KeyCode::Esc => self.show_event_log = false,
                KeyCode::Char('j') | KeyCode::Down => {
                    let max = self.event_ring.len().saturating_sub(1);
                    if self.event_log_scroll < max {
                        self.event_log_scroll += 1;
                    }
                }
                KeyCode::Char('k') | KeyCode::Up
                    if self.event_log_scroll > 0 => {
                        self.event_log_scroll -= 1;
                    }
                KeyCode::Char('g') | KeyCode::Home => {
                    self.event_log_scroll = 0;
                }
                KeyCode::Char('G') | KeyCode::End => {
                    self.event_log_scroll = self.event_ring.len().saturating_sub(1);
                }
                _ => {}
            }
            // Toggling Shift+E off while it's open still falls through
            // to the table below — keep that behavior.
            if !matches!(key.code, KeyCode::Char('E')) {
                return None;
            }
        }

        // Playlist scope picker overlay (task #73) — modal, intercepts
        // all keys while open.
        if self.playlist_picker.is_some() {
            if let Some(consumed) = self.handle_playlist_picker_key(&key) {
                return consumed;
            }
        }

        // Patreon detail-pane intercept (task #69): when the focused
        // channel is a Patreon creator, j/k move the post cursor, p/Enter
        // pull the selected post, t toggles auto-pull. `Some(_)` means the
        // key was consumed (inner option may carry an action); `None`
        // falls through to the normal keymap dispatch below.
        if self.active_pane == ActivePane::Detail {
            if let Some(consumed) = self.handle_patreon_detail_key(&key) {
                return consumed;
            }
        }

        // Central dispatch — consult the keymap table. Layer is derived
        // from active_pane, with Global as the fallback.
        let layer = crate::tui::keymap::Layer::for_pane(&self.active_pane)
            .unwrap_or(crate::tui::keymap::Layer::Global);
        if let Some(action) = crate::tui::keymap::lookup(layer, &key) {
            if let Some(app_action) = self.apply_key_action(action) {
                return Some(app_action);
            }
            return None;
        }

        match self.active_pane {
            ActivePane::Sidebar => self.handle_sidebar_key(key),
            ActivePane::Detail => self.handle_detail_key(key),
            ActivePane::RecordingList => self.handle_recording_list_key(key),
            ActivePane::Settings => self.handle_settings_key(key),
            ActivePane::Log => self.handle_log_key(key),
            ActivePane::Wizard => self.handle_wizard_key(key),
            ActivePane::Schedule => self.handle_schedule_key(key),
            // Plugin key events handled by caller which owns the registry
            ActivePane::Plugin(_) => None,
            ActivePane::StatusBar => self.handle_status_bar_key(key),
        }
    }

    /// Schedule pane: j/k navigate, D delete current row (writes config),
    /// Esc/h returns to Sidebar. Add/edit modals are deferred until the
    /// generic text-input modal lands (alongside rename/move in M1.3.b).
    fn handle_schedule_key(&mut self, _key: crossterm::event::KeyEvent) -> Option<AppAction> {
        // Schedule pane bindings all live in src/tui/keymap.rs and route
        // through apply_key_action / schedule_delete_selected.
        None
    }

    /// Open the theme picker, snapshot current theme so Esc can revert.
    pub fn open_theme_picker(&mut self) {
        let themes = crate::tui::theme::available_themes();
        if themes.is_empty() {
            self.status_message = "No themes found".to_string();
            return;
        }
        let current = crate::tui::theme::Theme::current_name();
        let selected = themes.iter().position(|t| *t == current).unwrap_or(0);
        self.theme_picker = Some(ThemePickerState {
            themes,
            selected,
            snapshot: crate::tui::theme::Theme::snapshot(),
            opened_at: std::time::Instant::now(),
        });
    }

    /// Apply the currently-selected picker theme as a transient preview.
    fn preview_picker_selection(&self) {
        let Some(ref state) = self.theme_picker else {
            return;
        };
        let Some(name) = state.themes.get(state.selected) else {
            return;
        };
        crate::tui::theme::Theme::set_with_overrides(
            name,
            self.config.theme.colors(),
            self.config.theme.ansi(),
        );
    }

    fn handle_theme_picker_key(&mut self, key: crossterm::event::KeyEvent) {
        use crossterm::event::KeyCode;
        let Some(state) = self.theme_picker.as_mut() else {
            return;
        };
        match key.code {
            KeyCode::Down | KeyCode::Char('j') => {
                if !state.themes.is_empty() {
                    state.selected = (state.selected + 1) % state.themes.len();
                }
                self.preview_picker_selection();
            }
            KeyCode::Up | KeyCode::Char('k') => {
                if !state.themes.is_empty() {
                    state.selected = if state.selected == 0 {
                        state.themes.len() - 1
                    } else {
                        state.selected - 1
                    };
                }
                self.preview_picker_selection();
            }
            KeyCode::Home | KeyCode::Char('g') => {
                state.selected = 0;
                self.preview_picker_selection();
            }
            KeyCode::End | KeyCode::Char('G') => {
                state.selected = state.themes.len().saturating_sub(1);
                self.preview_picker_selection();
            }
            KeyCode::Char('r') | KeyCode::Char('R') => {
                let current_name = state
                    .themes
                    .get(state.selected)
                    .cloned()
                    .unwrap_or_default();
                let rescanned = crate::tui::theme::available_themes();
                let new_selected = rescanned
                    .iter()
                    .position(|t| *t == current_name)
                    .unwrap_or(0);
                state.themes = rescanned;
                state.selected = new_selected;
                self.preview_picker_selection();
                self.status_message = "Themes rescanned".to_string();
            }
            KeyCode::Enter => {
                let picked = state
                    .themes
                    .get(state.selected)
                    .cloned()
                    .unwrap_or_default();
                self.theme_picker = None;
                if !picked.is_empty() {
                    self.config.theme.set_name(picked.clone());
                    if let Err(e) = self.config.save(None) {
                        tracing::warn!("theme picker: save failed: {e}");
                        self.status_message = format!("Theme save failed: {e}");
                    } else {
                        self.status_message = format!("Theme: {picked}");
                    }
                }
            }
            KeyCode::Esc => {
                let snap = state.snapshot.clone();
                self.theme_picker = None;
                crate::tui::theme::Theme::restore(snap);
            }
            _ => {}
        }
    }

    fn handle_wizard_key(&mut self, key: crossterm::event::KeyEvent) -> Option<AppAction> {
        use crossterm::event::KeyCode;
        match key.code {
            KeyCode::Char('o') | KeyCode::Char('O') => {
                // Open the current device-code verification URL in the
                // default browser. When nothing is pending we fall through.
                if let Some((_, ref uri, _)) = self.pending_auth {
                    let url = uri.clone();
                    self.status_message = format!("Opening {url}…");
                    return Some(AppAction::OpenUrl { url });
                }
            }
            KeyCode::Char('q') => {
                self.should_quit = true;
            }
            KeyCode::Esc => {
                // Users who want to inspect the TUI without credentials.
                self.active_pane = ActivePane::Sidebar;
                if self.channels.is_empty() {
                    self.status_message =
                        "No channels configured \u{2014} press S for Settings".to_string();
                }
            }
            _ => {}
        }
        None
    }

    // ---- Pane-context-sensitive nav helpers — invoked from apply_key_action ----

    fn pane_nav_down(&mut self) {
        match self.active_pane {
            ActivePane::Sidebar | ActivePane::Detail => self.navigate_channel(true),
            ActivePane::RecordingList => {
                let n = self.sorted_recordings().len();
                if n == 0 {
                    return;
                }
                self.selected_recording = (self.selected_recording + 1) % n;
                self.remember_recording_selection();
                if self.input_mode == InputMode::Visual {
                    self.recording_list_extend_selection();
                }
            }
            ActivePane::Schedule => {
                let n = self.config.schedule.len();
                if n > 0 {
                    self.selected_schedule = (self.selected_schedule + 1) % n;
                }
            }
            ActivePane::Settings => {
                use crate::tui::widgets::settings as sw;
                let rows = sw::settings_rows(self);
                let n = sw::selectable_indices(&rows).len();
                if n > 0 {
                    self.settings_selected = (self.settings_selected + 1) % n;
                }
            }
            ActivePane::Log
                if self.log_scroll + 1 < self.log_lines.len() => {
                    self.log_scroll += 1;
                    self.log_auto_scroll = false;
                }
            _ => {}
        }
    }

    fn pane_nav_up(&mut self) {
        match self.active_pane {
            ActivePane::Sidebar | ActivePane::Detail => self.navigate_channel(false),
            ActivePane::RecordingList => {
                let n = self.sorted_recordings().len();
                if n == 0 {
                    return;
                }
                self.selected_recording = if self.selected_recording == 0 {
                    n - 1
                } else {
                    self.selected_recording - 1
                };
                self.remember_recording_selection();
                if self.input_mode == InputMode::Visual {
                    self.recording_list_extend_selection();
                }
            }
            ActivePane::Schedule => {
                let n = self.config.schedule.len();
                if n > 0 {
                    self.selected_schedule = if self.selected_schedule == 0 {
                        n - 1
                    } else {
                        self.selected_schedule - 1
                    };
                }
            }
            ActivePane::Settings => {
                use crate::tui::widgets::settings as sw;
                let rows = sw::settings_rows(self);
                let n = sw::selectable_indices(&rows).len();
                if n > 0 {
                    self.settings_selected = if self.settings_selected == 0 {
                        n - 1
                    } else {
                        self.settings_selected - 1
                    };
                }
            }
            ActivePane::Log => {
                self.log_scroll = self.log_scroll.saturating_sub(1);
                self.log_auto_scroll = false;
            }
            _ => {}
        }
    }

    fn pane_nav_top(&mut self) {
        match self.active_pane {
            ActivePane::Sidebar | ActivePane::Detail => self.jump_channel_to(true),
            ActivePane::RecordingList
                if !self.sorted_recordings().is_empty() => {
                    self.selected_recording = 0;
                    self.remember_recording_selection();
                }
            ActivePane::Schedule
                if !self.config.schedule.is_empty() => {
                    self.selected_schedule = 0;
                }
            ActivePane::Settings => {
                self.settings_selected = 0;
            }
            ActivePane::Log => {
                self.log_scroll = 0;
                self.log_auto_scroll = false;
            }
            _ => {}
        }
    }

    fn pane_nav_bottom(&mut self) {
        match self.active_pane {
            ActivePane::Sidebar | ActivePane::Detail => self.jump_channel_to(false),
            ActivePane::RecordingList => {
                let n = self.sorted_recordings().len();
                if n > 0 {
                    self.selected_recording = n - 1;
                    self.remember_recording_selection();
                }
            }
            ActivePane::Schedule => {
                let n = self.config.schedule.len();
                if n > 0 {
                    self.selected_schedule = n - 1;
                }
            }
            ActivePane::Settings => {
                use crate::tui::widgets::settings as sw;
                let rows = sw::settings_rows(self);
                let n = sw::selectable_indices(&rows).len();
                if n > 0 {
                    self.settings_selected = n - 1;
                }
            }
            ActivePane::Log => {
                self.log_scroll = self.log_lines.len().saturating_sub(1);
                self.log_auto_scroll = true;
            }
            _ => {}
        }
    }

    fn pane_nav_back(&mut self) {
        // Esc / h / Left: first clears Visual mode (yazi convention —
        // selection persists; explicit Ctrl+v clears it). Then clears
        // the search filter if active. Only then walks the pane back
        // to Sidebar.
        if self.input_mode == InputMode::Visual {
            self.input_mode = InputMode::Normal;
            return;
        }
        if !self.search_query.is_empty() {
            self.clear_search();
            return;
        }
        match self.active_pane {
            ActivePane::Detail
            | ActivePane::RecordingList
            | ActivePane::Settings
            | ActivePane::Log
            | ActivePane::Schedule => {
                if matches!(self.active_pane, ActivePane::Settings) {
                    let _ = self.config.save(None);
                }
                self.active_pane = ActivePane::Sidebar;
            }
            _ => {}
        }
    }

    fn pane_nav_activate(&mut self) -> Option<AppAction> {
        match self.active_pane {
            ActivePane::Sidebar => {
                if !self.channels.is_empty() {
                    self.active_pane = ActivePane::Detail;
                }
                None
            }
            ActivePane::Settings => {
                use crate::tui::widgets::settings as sw;
                let rows = sw::settings_rows(self);
                let selectable = sw::selectable_indices(&rows);
                if let Some(&full_idx) = selectable.get(self.settings_selected) {
                    if let Some(row) = rows.get(full_idx).cloned() {
                        self.apply_settings_row(&row);
                    }
                }
                None
            }
            ActivePane::Schedule => {
                if let Some(entry) = self.config.schedule.get(self.selected_schedule) {
                    let index = self.selected_schedule;
                    let cron = entry.cron.clone();
                    self.open_text_input(
                        crate::tui::widgets::text_input::TextInputPurpose::ScheduleEditCron {
                            index,
                        },
                        "Edit cron expression",
                        cron,
                    );
                }
                None
            }
            _ => None,
        }
    }

    // ---- Pane-action helpers ----

    /// Start or stop a per-channel bulk back-catalog download on the
    /// selected channel (task #71). Bulk DL runs in the daemon, so this
    /// only works when connected over IPC; in standalone mode we tell the
    /// user to use the `pull` CLI.
    fn toggle_bulk_download_on_selected(&mut self) {
        let Some(ch) = self.channels.get(self.selected_channel) else {
            return;
        };
        let channel_id = ch.id.clone();
        let channel_name = ch.display_name.clone();
        let platform = ch.platform;

        let Some(ref tx) = self.daemon_tx else {
            self.status_message =
                "Bulk download needs the daemon — run `strivo daemon` or use `strivo pull`"
                    .to_string();
            return;
        };

        let currently_active = self
            .bulk_downloads
            .get(&channel_id)
            .map(|s| s.active)
            .unwrap_or(false);
        let action = if currently_active {
            crate::ipc::BulkAction::Stop
        } else {
            crate::ipc::BulkAction::Start
        };
        let verb = if currently_active { "Stopping" } else { "Starting" };
        let _ = tx.send(crate::ipc::ClientMessage::BulkDownload {
            channel_id,
            channel_name: channel_name.clone(),
            platform,
            action,
            playlist_id: None,
        });
        self.status_message = format!("{verb} bulk download for {channel_name}…");
    }

    /// Per-platform bulk-DL master switch (task #72): start (or stop)
    /// bulk back-catalog downloads for every channel of the selected
    /// channel's platform at once. If any channel of that platform is
    /// currently downloading, the switch stops them all; otherwise it
    /// starts them all. Fans the per-channel IPC command (#71) across
    /// the platform — the daemon dedups already-running channels.
    fn toggle_bulk_download_platform(&mut self) {
        let Some(ch) = self.channels.get(self.selected_channel) else {
            return;
        };
        let platform = ch.platform;

        let Some(tx) = self.daemon_tx.clone() else {
            self.status_message =
                "Bulk download needs the daemon — run `strivo daemon`".to_string();
            return;
        };

        let targets: Vec<(String, String)> = self
            .channels
            .iter()
            .filter(|c| c.platform == platform)
            .map(|c| (c.id.clone(), c.display_name.clone()))
            .collect();
        if targets.is_empty() {
            return;
        }

        // Stop-all if any target is active; otherwise start-all.
        let any_active = targets
            .iter()
            .any(|(id, _)| self.bulk_downloads.get(id).is_some_and(|s| s.active));
        let action = if any_active {
            crate::ipc::BulkAction::Stop
        } else {
            crate::ipc::BulkAction::Start
        };

        for (channel_id, channel_name) in &targets {
            let _ = tx.send(crate::ipc::ClientMessage::BulkDownload {
                channel_id: channel_id.clone(),
                channel_name: channel_name.clone(),
                platform,
                action: action.clone(),
                playlist_id: None,
            });
        }
        let verb = if any_active { "Stopping" } else { "Starting" };
        self.status_message = format!(
            "{verb} bulk download for all {} {} channels…",
            targets.len(),
            platform
        );
    }

    /// Open the YouTube playlist scope picker for the selected channel
    /// (task #73) and request its playlists from the daemon.
    fn open_playlist_picker(&mut self) {
        let Some(ch) = self.channels.get(self.selected_channel) else {
            return;
        };
        if ch.platform != PlatformKind::YouTube {
            self.status_message = "Playlist scope is YouTube-only".to_string();
            return;
        }
        let channel_id = ch.id.clone();
        let channel_name = ch.display_name.clone();
        let Some(ref tx) = self.daemon_tx else {
            self.status_message = "Playlist scope needs the daemon".to_string();
            return;
        };
        let _ = tx.send(crate::ipc::ClientMessage::ListPlaylists {
            channel_id: channel_id.clone(),
        });
        self.playlist_picker = Some(PlaylistPicker {
            channel_id,
            channel_name,
            playlists: Vec::new(),
            selected: 0,
            loading: true,
        });
        self.status_message = "Loading playlists…".to_string();
    }

    /// Handle a key while the playlist picker overlay is open (task #73).
    /// Returns Some(consumed) when handled. Row 0 = whole channel.
    fn handle_playlist_picker_key(
        &mut self,
        key: &crossterm::event::KeyEvent,
    ) -> Option<Option<AppAction>> {
        use crossterm::event::KeyCode;
        let picker = self.playlist_picker.as_mut()?;
        let row_count = picker.playlists.len() + 1; // +1 for "Whole channel"
        match key.code {
            KeyCode::Esc => {
                self.playlist_picker = None;
                Some(None)
            }
            KeyCode::Char('j') | KeyCode::Down => {
                picker.selected = (picker.selected + 1).min(row_count - 1);
                Some(None)
            }
            KeyCode::Char('k') | KeyCode::Up => {
                picker.selected = picker.selected.saturating_sub(1);
                Some(None)
            }
            KeyCode::Enter => {
                let picker = self.playlist_picker.take().unwrap();
                let (playlist_id, scope_label) = if picker.selected == 0 {
                    (None, "whole channel".to_string())
                } else {
                    let pl = &picker.playlists[picker.selected - 1];
                    (Some(pl.id.clone()), pl.title.clone())
                };
                if let Some(ref tx) = self.daemon_tx {
                    let _ = tx.send(crate::ipc::ClientMessage::BulkDownload {
                        channel_id: picker.channel_id,
                        channel_name: picker.channel_name.clone(),
                        platform: PlatformKind::YouTube,
                        action: crate::ipc::BulkAction::Start,
                        playlist_id,
                    });
                    self.status_message =
                        format!("Bulk download: {} ({scope_label})", picker.channel_name);
                }
                Some(None)
            }
            _ => Some(None), // swallow other keys while the overlay is open
        }
    }

    fn toggle_auto_record_on_selected(&mut self) {
        let Some(idx) = self
            .channels
            .get(self.selected_channel)
            .map(|_| self.selected_channel)
        else {
            return;
        };
        let (id, plat, name, display, was_on, format) = {
            let ch = &self.channels[idx];
            (
                ch.id.clone(),
                ch.platform.to_string(),
                ch.name.clone(),
                ch.display_name.clone(),
                ch.auto_record,
                self.config
                    .auto_record_channels
                    .iter()
                    .find(|a| a.channel_id == ch.id && a.platform == ch.platform.to_string())
                    .and_then(|a| a.format.clone()),
            )
        };
        // Snapshot the pre-mutation state for undo.
        self.push_undo(UndoAction::ToggleAutoRecord {
            channel_id: id.clone(),
            platform: plat.clone(),
            was_on,
            channel_name: name.clone(),
            format: format.clone(),
        });

        let ch = &mut self.channels[idx];
        ch.auto_record = !was_on;
        if ch.auto_record {
            self.config
                .auto_record_channels
                .push(crate::config::AutoRecordEntry {
                    platform: plat.clone(),
                    channel_id: id.clone(),
                    channel_name: name,
                    format: None,
                    profile: None,
                });
            self.status_message = format!("Monitor ON for {display}");
        } else {
            self.config
                .auto_record_channels
                .retain(|a| !(a.channel_id == id && a.platform == plat));
            self.status_message = format!("Monitor OFF for {display}");
        }
        self.rebuild_sidebar_order();
        if let Err(e) = self.config.save(None) {
            self.status_message = format!("Failed to save config: {e}");
        }
    }

    fn start_recording_on_selected(&mut self, from_start: bool) -> Option<AppAction> {
        let ch = self.selected_channel()?;
        if !ch.is_live {
            self.status_message = "Channel is not live".to_string();
            return None;
        }
        if self.is_channel_recording(&ch.id) {
            self.status_message = format!("Already recording {}", ch.display_name);
            return None;
        }
        let ch = ch.clone();
        Some(AppAction::StartRecording {
            channel_id: ch.id,
            channel_name: ch.name,
            display_name: Some(ch.display_name),
            platform: ch.platform,
            transcode: self.transcode_mode,
            from_start,
        })
    }

    fn watch_selected_stream(&mut self) -> Option<AppAction> {
        let ch = self.selected_channel()?;
        if !ch.is_live {
            self.status_message = "Channel is not live".to_string();
            return None;
        }
        let ch = ch.clone();
        self.watching_channel = Some(ch.name.clone());
        Some(AppAction::Watch {
            channel_name: ch.name,
            platform: ch.platform,
        })
    }

    fn recording_list_stop_selected(&mut self) -> Option<AppAction> {
        let recs = self.sorted_recordings();
        let rec = recs.get(self.selected_recording)?;
        if matches!(
            rec.state,
            RecordingState::Recording | RecordingState::ResolvingUrl
        ) {
            let job_id = rec.id;
            self.send_recording_command(RecordingCommand::Stop { job_id });
            self.status_message = format!("Stopping recording: {}", rec.channel_name);
        }
        None
    }

    fn recording_list_play_selected(&mut self) -> Option<AppAction> {
        let recs = self.sorted_recordings();
        let rec = recs.get(self.selected_recording)?;
        if rec.state != RecordingState::Finished {
            return None;
        }
        let job_id = rec.id;
        let path = rec.output_path.clone();
        if let Some(job) = self.recordings.get_mut(&job_id) {
            job.watched = true;
        }
        self.state.watched.insert(job_id);
        self.state.save();
        Some(AppAction::PlayFile { path })
    }

    fn recording_list_open_props(&mut self) -> Option<AppAction> {
        let recs = self.sorted_recordings();
        let rec = recs.get(self.selected_recording)?;
        let job_id = rec.id;
        let path = rec.output_path.clone();
        self.show_properties = Some(job_id);
        if !self.media_info_cache.contains_key(&job_id) {
            return Some(AppAction::ProbeMedia { job_id, path });
        }
        None
    }

    fn recording_list_toggle_select(&mut self) {
        let recs = self.sorted_recordings();
        let Some(rec) = recs.get(self.selected_recording) else {
            return;
        };
        let id = rec.id;
        if self.recording_selections_set.remove(&id) {
            self.recording_selections_order.retain(|x| *x != id);
        } else {
            self.recording_selections_set.insert(id);
            self.recording_selections_order.push(id);
        }
    }

    /// Add the current recording-list row to the selection (insertion-
    /// order preserved, dedup). Called from Visual mode after every
    /// j/k movement so the highlight tail follows the cursor.
    fn recording_list_extend_selection(&mut self) {
        let recs = self.sorted_recordings();
        let Some(rec) = recs.get(self.selected_recording) else {
            return;
        };
        let id = rec.id;
        if self.recording_selections_set.insert(id) {
            self.recording_selections_order.push(id);
        }
    }

    fn recording_list_trash_selected(&mut self) {
        let mut targets: Vec<Uuid> = if self.recording_selections_order.is_empty() {
            let recs = self.sorted_recordings();
            recs.get(self.selected_recording)
                .map(|r| r.id)
                .into_iter()
                .collect()
        } else {
            self.recording_selections_order.clone()
        };
        if targets.is_empty() {
            return;
        }
        targets.retain(|id| {
            self.recordings
                .get(id)
                .map(|j| {
                    !matches!(
                        j.state,
                        RecordingState::Recording | RecordingState::ResolvingUrl
                    )
                })
                .unwrap_or(false)
        });
        let mut trashed = 0usize;
        let mut errors = 0usize;
        // Capture (original job, trash path) tuples for undo. Only the
        // jobs whose move-to-trash succeeded participate — a failed
        // move leaves the file in place and the job in memory.
        let mut undo_items: Vec<(crate::recording::job::RecordingJob, PathBuf)> = Vec::new();
        for id in &targets {
            if let Some(job) = self.recordings.get(id).cloned() {
                match crate::recording::trash::move_to_trash(&job.output_path) {
                    Ok(new_path) => {
                        tracing::info!(job_id = %id, new_path = %new_path.display(), "recording moved to trash");
                        undo_items.push((job, new_path));
                        trashed += 1;
                    }
                    Err(e) => {
                        tracing::warn!(job_id = %id, error = %e, "trash failed");
                        errors += 1;
                    }
                }
            }
        }
        if !undo_items.is_empty() {
            self.push_undo(UndoAction::TrashRecording { items: undo_items });
        }
        for id in &targets {
            self.recordings.remove(id);
        }
        self.recording_selections_order.clear();
        self.recording_selections_set.clear();
        self.rebuild_active_channels();
        self.rebuild_sidebar_order();
        self.reconcile_selected_recording();
        self.status_message = if errors == 0 {
            format!("Trashed {trashed} recording(s) · u to undo")
        } else {
            format!("Trashed {trashed}, {errors} failed (see log)")
        };
    }

    /// Push a reversible action onto the bounded undo stack. Oldest
    /// entries fall off the front when capacity is exceeded; they're
    /// irrecoverable but the user retains five operations of history.
    fn push_undo(&mut self, action: UndoAction) {
        if self.undo_stack.len() >= UNDO_DEPTH {
            self.undo_stack.pop_front();
        }
        self.undo_stack.push_back(action);
    }

    /// Pop and apply the most recent undoable action.
    fn undo_last(&mut self) {
        let Some(action) = self.undo_stack.pop_back() else {
            self.status_message = "Nothing to undo".into();
            return;
        };
        match action {
            UndoAction::ToggleAutoRecord {
                channel_id,
                platform,
                was_on,
                channel_name,
                format,
            } => {
                if let Some(ch) = self
                    .channels
                    .iter_mut()
                    .find(|c| c.id == channel_id && c.platform.to_string() == platform)
                {
                    ch.auto_record = was_on;
                }
                if was_on {
                    // Was on before the toggle that turned it off — restore the entry.
                    self.config
                        .auto_record_channels
                        .push(crate::config::AutoRecordEntry {
                            platform: platform.clone(),
                            channel_id: channel_id.clone(),
                            channel_name,
                            format,
                            profile: None,
                        });
                } else {
                    self.config
                        .auto_record_channels
                        .retain(|a| !(a.channel_id == channel_id && a.platform == platform));
                }
                self.rebuild_sidebar_order();
                let _ = self.config.save(None);
                self.status_message = "Undo: auto-record toggle".into();
            }
            UndoAction::ScheduleDelete { index, entry } => {
                let i = index.min(self.config.schedule.len());
                self.config.schedule.insert(i, entry);
                let _ = self.config.save(None);
                self.status_message = "Undo: schedule restored".into();
            }
            UndoAction::TrashRecording { items } => {
                let n = items.len();
                for (job, trash_path) in items {
                    let dest = job.output_path.clone();
                    if let Some(parent) = dest.parent() {
                        let _ = std::fs::create_dir_all(parent);
                    }
                    if let Err(e) = std::fs::rename(&trash_path, &dest) {
                        tracing::warn!(
                            from = %trash_path.display(),
                            to = %dest.display(),
                            error = %e,
                            "undo: trash restore failed",
                        );
                        continue;
                    }
                    self.recordings.insert(job.id, job);
                }
                self.rebuild_active_channels();
                self.rebuild_sidebar_order();
                self.reconcile_selected_recording();
                self.status_message = format!("Undo: restored {n} recording(s)");
            }
        }
    }

    fn recording_list_open_rename(&mut self) {
        let recs = self.sorted_recordings();
        let Some(rec) = recs.get(self.selected_recording) else {
            return;
        };
        let job_id = rec.id;
        let initial = rec
            .output_path
            .file_stem()
            .and_then(|s| s.to_str())
            .unwrap_or("")
            .to_string();
        self.open_text_input(
            crate::tui::widgets::text_input::TextInputPurpose::RenameRecording { job_id },
            "Rename recording (no extension required)",
            initial,
        );
    }

    fn recording_list_open_move(&mut self) {
        let recs = self.sorted_recordings();
        let Some(rec) = recs.get(self.selected_recording) else {
            return;
        };
        let job_id = rec.id;
        let initial = rec
            .output_path
            .parent()
            .map(|p| p.display().to_string())
            .unwrap_or_default();
        self.open_text_input(
            crate::tui::widgets::text_input::TextInputPurpose::MoveRecording { job_id },
            "Move to directory (~ expands)",
            initial,
        );
    }

    fn schedule_delete_selected(&mut self) {
        let count = self.config.schedule.len();
        if count == 0 {
            return;
        }
        if self.selected_schedule >= count {
            return;
        }
        let index = self.selected_schedule;
        let removed = self.config.schedule.remove(index);
        // Record for undo before we save so a save failure doesn't
        // leave the stack lying about a non-persisted mutation.
        self.push_undo(UndoAction::ScheduleDelete {
            index,
            entry: removed.clone(),
        });
        if let Err(e) = self.config.save(None) {
            self.status_message = format!("Schedule removed in-memory but save failed: {e}");
        } else {
            self.status_message = format!(
                "Removed schedule for {} ({})",
                removed.channel, removed.cron
            );
        }
        let new_count = self.config.schedule.len();
        if new_count == 0 {
            self.selected_schedule = 0;
        } else if self.selected_schedule >= new_count {
            self.selected_schedule = new_count - 1;
        }
    }

