    /// Actions popup key handler. (D5.)
    fn handle_actions_popup_key(
        &mut self,
        key: crossterm::event::KeyEvent,
    ) -> Option<AppAction> {
        use crossterm::event::KeyCode;
        let popup = self.actions_popup.as_mut()?;
        match key.code {
            KeyCode::Esc => {
                self.actions_popup = None;
                None
            }
            KeyCode::Up => {
                popup.selected = popup.selected.saturating_sub(1);
                None
            }
            KeyCode::Down => {
                if popup.selected + 1 < popup.entries.len() {
                    popup.selected += 1;
                }
                None
            }
            KeyCode::Home => {
                popup.selected = 0;
                None
            }
            KeyCode::End => {
                popup.selected = popup.entries.len().saturating_sub(1);
                None
            }
            KeyCode::Enter => {
                use crate::tui::widgets::actions_popup::ActionDispatch;
                let dispatch = popup
                    .entries
                    .get(popup.selected)
                    .map(|e| e.dispatch.clone());
                self.actions_popup = None;
                match dispatch {
                    Some(ActionDispatch::KeyAction(a)) => {
                        return self.apply_key_action(a);
                    }
                    Some(ActionDispatch::PluginVerb { plugin, verb }) => {
                        // M2 — stash for the host loop to drain on the
                        // next tick. The loop has the PluginRegistry
                        // handle and routes through registry.dispatch_verb;
                        // returned PluginActions are processed inline.
                        // Selection is the multi-set when non-empty,
                        // else the cursor row.
                        let selection: Vec<uuid::Uuid> =
                            if !self.recording_selections_set.is_empty() {
                                self.recording_selections_order.clone()
                            } else {
                                self.selected_recording_id.into_iter().collect()
                            };
                        self.pending_plugin_verb = Some(PendingPluginVerb {
                            plugin,
                            verb,
                            selection,
                        });
                        self.status_message = format!("→ {plugin}: {verb}");
                    }
                    None => {}
                }
                None
            }
            _ => None,
        }
    }

    /// Palette overlay key handler. Owns up/down/Esc/Enter/Tab and
    /// passes typed characters straight into the query. The result
    /// list is recomputed on render so we only need to keep the
    /// query + cursor + selected index in sync here. (D4 + X4.)
    fn handle_palette_key(
        &mut self,
        key: crossterm::event::KeyEvent,
    ) -> Option<AppAction> {
        use crate::app::PaletteScope;
        use crate::tui::widgets::palette::PaletteDispatch;
        use crossterm::event::KeyCode;
        let state = self.palette.as_mut()?;
        match key.code {
            KeyCode::Esc => {
                self.palette = None;
                return None;
            }
            KeyCode::Up => {
                state.selected = state.selected.saturating_sub(1);
                return None;
            }
            KeyCode::Down => {
                // No bound — render clamps to the result count; we
                // saturate at usize::MAX safely.
                state.selected = state.selected.saturating_add(1);
                return None;
            }
            KeyCode::Home => state.selected = 0,
            KeyCode::End => state.selected = usize::MAX,
            KeyCode::Backspace => {
                if state.cursor > 0 {
                    let chars: Vec<char> = state.query.chars().collect();
                    let cur = state.cursor.min(chars.len());
                    let new: String = chars[..cur - 1]
                        .iter()
                        .chain(chars[cur..].iter())
                        .collect();
                    state.query = new;
                    state.cursor -= 1;
                    state.selected = 0;
                }
                return None;
            }
            KeyCode::Left => {
                state.cursor = state.cursor.saturating_sub(1);
                return None;
            }
            KeyCode::Right => {
                let len = state.query.chars().count();
                if state.cursor < len {
                    state.cursor += 1;
                }
                return None;
            }
            KeyCode::Tab => {
                // Tab — toggle scope from the typed query. Equivalent
                // to typing `:scope` and pressing Enter, but with one
                // keystroke. Falls through to Enter logic when no
                // valid scope is in the query.
                let trimmed = state.query.trim().trim_start_matches(':');
                if let Some(scope) = PaletteScope::parse(trimmed) {
                    state.scope = Some(scope);
                    state.query.clear();
                    state.cursor = 0;
                    state.selected = 0;
                    return None;
                }
            }
            KeyCode::Enter => {
                // Drop the &mut borrow; dispatch happens after the
                // match so we can re-borrow self for build_rows.
            }
            KeyCode::Char(c) => {
                // Append at cursor.
                let mut chars: Vec<char> = state.query.chars().collect();
                let cur = state.cursor.min(chars.len());
                chars.insert(cur, c);
                state.query = chars.into_iter().collect();
                state.cursor += 1;
                state.selected = 0;
                return None;
            }
            _ => return None,
        }

        // Enter falls through here. Build rows from the *current*
        // palette state (which requires &self), then dispatch.
        if matches!(key.code, KeyCode::Enter) {
            let selected = self.palette.as_ref().map(|s| s.selected).unwrap_or(0);
            let dummy_reg = crate::plugin::registry::PluginRegistry::new();
            // The palette renderer reads from the live registry too;
            // we don't carry it through to apply_key_action, so plugin
            // pane activation is handled out of band by the runtime
            // loop (it sees the same KeyAction and routes). For now
            // limit dispatch to KeyAction + scope switching.
            let rows = crate::tui::widgets::palette::build_rows(self, &dummy_reg);
            if let Some(row) = rows.get(selected) {
                match &row.dispatch {
                    PaletteDispatch::KeyAction(action) => {
                        let action = *action;
                        let label = row.label.clone();
                        self.palette = None;
                        self.command_log.push(label.clone());
                        if self.command_log.len() > 256 {
                            self.command_log.remove(0);
                        }
                        let next = self.apply_key_action(action);
                        self.status_message = format!("→ {label}");
                        return next;
                    }
                    PaletteDispatch::SwitchScope(scope) => {
                        let s = *scope;
                        if let Some(p) = self.palette.as_mut() {
                            p.scope = Some(s);
                            p.query.clear();
                            p.cursor = 0;
                            p.selected = 0;
                        }
                    }
                    PaletteDispatch::PluginPane(_) => {
                        // Plugin pane activation isn't wired through
                        // apply_key_action; close the palette and let
                        // the user use the plugin's own activation key.
                        // Refine when D4 + plugin namespace land
                        // together.
                        self.palette = None;
                    }
                    PaletteDispatch::LocalAction(local) => {
                        use crate::tui::widgets::palette::PaletteLocal;
                        let local = *local;
                        self.palette = None;
                        match local {
                            PaletteLocal::SavePreset => {
                                // Defer the actual save until the user
                                // supplies a name. Open a text input
                                // with the SavePreset purpose; the
                                // submit handler calls recorder::save.
                                self.open_text_input(
                                    crate::tui::widgets::text_input::TextInputPurpose::PaletteSavePreset,
                                    "Save preset as",
                                    "",
                                );
                            }
                            PaletteLocal::ClearLog => {
                                let n = self.command_log.len();
                                self.command_log.clear();
                                self.status_message =
                                    format!("command log cleared ({n} entries)");
                            }
                            PaletteLocal::ListPresets => {
                                let presets = crate::edl::recorder::list();
                                self.status_message = if presets.is_empty() {
                                    "no presets saved (palette:save-preset to make one)"
                                        .to_string()
                                } else {
                                    format!(
                                        "{} preset(s): {}",
                                        presets.len(),
                                        presets
                                            .iter()
                                            .map(|p| p.name.as_str())
                                            .collect::<Vec<_>>()
                                            .join(", ")
                                    )
                                };
                            }
                        }
                    }
                }
            } else {
                self.palette = None;
            }
        }
        None
    }

    fn handle_status_bar_key(&mut self, key: crossterm::event::KeyEvent) -> Option<AppAction> {
        use crate::tui::widgets::status_bar::configured_platforms;
        use crossterm::event::KeyCode;

        let platforms = configured_platforms(self);
        if platforms.is_empty() {
            self.active_pane = self.prev_pane.take().unwrap_or(ActivePane::Sidebar);
            return None;
        }

        match key.code {
            KeyCode::Char('l') | KeyCode::Right => {
                self.selected_indicator = (self.selected_indicator + 1) % platforms.len();
            }
            KeyCode::Char('h') | KeyCode::Left => {
                self.selected_indicator = if self.selected_indicator == 0 {
                    platforms.len() - 1
                } else {
                    self.selected_indicator - 1
                };
            }
            KeyCode::Enter => {
                if let Some(&kind) = platforms.get(self.selected_indicator) {
                    self.show_platform_debug = Some(kind);
                }
            }
            KeyCode::Esc => {
                self.active_pane = self.prev_pane.take().unwrap_or(ActivePane::Sidebar);
            }
            _ => {}
        }
        None
    }

